#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "./../main.h"

#define NUMBER_THREADS 128
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

void kernel_cpu(par_str d_par_gpu,
                dim_str d_dim_gpu,
                box_str* d_box_gpu,
                FOUR_VECTOR* d_rv_gpu,
                fp* d_qv_gpu,
                FOUR_VECTOR* d_fv_gpu)
{
    int bx;

    #pragma omp parallel for private(bx) schedule(static)
    for (bx = 0; bx < d_dim_gpu.number_boxes; bx++) {
        fp a2 = 2.0 * d_par_gpu.alpha * d_par_gpu.alpha;

        int first_i = d_box_gpu[bx].offset;
        FOUR_VECTOR* rA = &d_rv_gpu[first_i];
        FOUR_VECTOR* fA = &d_fv_gpu[first_i];

        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
            rA_shared[wtx] = rA[wtx];
        }

        for (int k = 0; k < (1 + d_box_gpu[bx].nn); k++) {
            int pointer;
            if (k == 0) {
                pointer = bx;
            } else {
                pointer = d_box_gpu[bx].nei[k - 1].number;
            }

            int first_j = d_box_gpu[pointer].offset;
            FOUR_VECTOR* rB = &d_rv_gpu[first_j];
            fp* qB = &d_qv_gpu[first_j];

            FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
            double qB_shared[NUMBER_PAR_PER_BOX];
            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
                rB_shared[wtx] = rB[wtx];
                qB_shared[wtx] = qB[wtx];
            }

            #pragma omp parallel for schedule(static)
            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
                fp r2, u2, vij, fs, fxij, fyij, fzij;
                THREE_VECTOR d;

                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT((fp)rA_shared[wtx], (fp)rB_shared[j]);
                    u2 = a2 * r2;
                    vij = exp(-u2);
                    fs = 2 * vij;

                    d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
                    fxij = fs * d.x;
                    d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
                    fyij = fs * d.y;
                    d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
                    fzij = fs * d.z;

                    #pragma omp atomic
                    fA[wtx].v += (double)((fp)qB_shared[j] * vij);
                    #pragma omp atomic
                    fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
                    #pragma omp atomic
                    fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
                    #pragma omp atomic
                    fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
                }
            }
        }
    }
}

#include "./kernel_gpu_cuda_wrapper.h"
#include "./../util/timer/timer.h"

void kernel_gpu_cuda_wrapper(par_str par_cpu,
                             dim_str dim_cpu,
                             box_str* box_cpu,
                             FOUR_VECTOR* rv_cpu,
                             fp* qv_cpu,
                             FOUR_VECTOR* fv_cpu)
{
    long long time0, time1, time2, time3, time4, time5, time6;

    time0 = get_time();

    // No device setup needed for OpenMP

    time1 = get_time();

    // Allocate memory on host (already allocated by caller)

    time2 = get_time();

    // Copy data to local pointers (no device copy needed)

    time3 = get_time();

    // Run kernel on CPU with OpenMP
    kernel_cpu(par_cpu,
               dim_cpu,
               box_cpu,
               rv_cpu,
               qv_cpu,
               fv_cpu);

    time4 = get_time();

    // No device to host copy needed

    time5 = get_time();

    // No device memory free needed

    time6 = get_time();

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n", (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", (float)(time6 - time5) / 1000000, (float)(time6 - time5) / (float)(time6 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time6 - time0) / 1000000);
}

